#!/usr/bin/env node
// Asserts the app version is consistent across the files that hold it, so a
// half-finished bump can't ship a binary stamped with the wrong number.
//
// Sources of truth for the *app* version (the parsers crate is independent and
// not checked here):
//   - package.json          → frontend banner (__APP_VERSION__) + Tauri app version
//   - src-tauri/tauri.conf.json → must inherit from package.json ("../package.json")
//   - src-tauri/Cargo.toml  → the Rust binary version
//   - Cargo.lock (root)     → locked tsmap version, regenerated by cargo
//
// Fails the build (exit 1) with a clear diff if any disagree. Run from predev
// and prebuild. To resolve a failure: bump the lagging file, then `cargo check`
// to refresh Cargo.lock.

import { readFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const ROOT = join(dirname(fileURLToPath(import.meta.url)), '..');

function read(rel) {
  return readFileSync(join(ROOT, rel), 'utf8');
}

function fail(msg) {
  console.error(`\n  ✗ version sync check failed\n\n${msg}\n`);
  process.exit(1);
}

// package.json — the canonical version everything else must match.
const pkgVersion = JSON.parse(read('package.json')).version;
if (!pkgVersion) fail('package.json has no "version" field.');

const mismatches = [];

// src-tauri/Cargo.toml — first `version = "..."` under [package].
const cargoToml = read('src-tauri/Cargo.toml');
const cargoTomlVersion = cargoToml.match(/^\s*version\s*=\s*"([^"]+)"/m)?.[1];
if (cargoTomlVersion !== pkgVersion) {
  mismatches.push(`    src-tauri/Cargo.toml      ${cargoTomlVersion ?? '(missing)'}`);
}

// Cargo.lock (root) — the [[package]] block whose name is "tsmap".
const cargoLock = read('Cargo.lock');
const lockVersion = cargoLock
  .match(/name = "tsmap"\nversion = "([^"]+)"/)?.[1];
if (lockVersion !== pkgVersion) {
  mismatches.push(`    Cargo.lock                ${lockVersion ?? '(missing)'}  →  run \`cargo check\` to refresh`);
}

// tauri.conf.json — must delegate to package.json, not hold its own number.
const tauriConf = JSON.parse(read('src-tauri/tauri.conf.json'));
if (tauriConf.version !== '../package.json') {
  mismatches.push(`    src-tauri/tauri.conf.json "${tauriConf.version}"  (expected "../package.json")`);
}

if (mismatches.length > 0) {
  fail(
    `  package.json is "${pkgVersion}" but these disagree:\n\n` +
    mismatches.join('\n') +
    `\n\n  Bump the lagging file(s) to ${pkgVersion}, then \`cargo check\` to refresh Cargo.lock.`,
  );
}

// Silent on success — keeps build output clean.
